// Extract sender_id, post_id (referenced reel/story if any), and message text from Meta IG DM webhook.
// Meta's IG messaging payload shape:
// body.entry[].messaging[].sender.id, .message.text, .message.reply_to.story.id (when replying to a reel/story)

const out = [];
for (const item of items) {
  try {
    const body = item.json.body || item.json;
    const entries = body.entry || [];
    for (const entry of entries) {
      const messagingArr = entry.messaging || [];
      for (const m of messagingArr) {
        // Skip echoes (messages sent BY the IG account itself)
        if (m.message && m.message.is_echo) continue;

        const sender_id = m.sender && m.sender.id ? String(m.sender.id) : '';
        const text = (m.message && m.message.text) ? String(m.message.text) : '';

        // post_id can be inferred from a story/reel reply context if present
        let post_id = '';
        if (m.message && m.message.reply_to) {
          if (m.message.reply_to.story && m.message.reply_to.story.id) {
            post_id = String(m.message.reply_to.story.id);
          } else if (m.message.reply_to.mid) {
            post_id = String(m.message.reply_to.mid);
          }
        }

        if (!sender_id || !text) continue; // ignore non-text events (delivery, reads, etc.)

        out.push({
          json: {
            sender_id,
            post_id,
            message_text: text,
            received_at: new Date().toISOString()
          }
        });
      }
    }
  } catch (err) {
    out.push({ json: { sender_id: '', post_id: '', message_text: '', error: 'extract_failed: ' + err.message } });
  }
}

if (out.length === 0) {
  return [{ json: { sender_id: '', post_id: '', message_text: '', skipped: true } }];
}
return out;

// Defensively pull text out of whatever Claude/Anthropic node response shape we got,
// strip code fences, JSON.parse with try/catch, merge sender_id/post_id from upstream.

const upstream = $('Extract DM Payload').first().json;
const sender_id = upstream.sender_id || '';
const post_id = upstream.post_id || '';
const message_text = upstream.message_text || '';

function pickText(j) {
  if (!j) return '';
  if (typeof j === 'string') return j;
  if (typeof j.text === 'string') return j.text;
  if (Array.isArray(j.content)) {
    return j.content.map(c => (c && (c.text || c.value)) || '').join('\n');
  }
  if (j.message && Array.isArray(j.message.content)) {
    return j.message.content.map(c => (c && (c.text || c.value)) || '').join('\n');
  }
  if (j.message && typeof j.message.content === 'string') return j.message.content;
  if (typeof j.output === 'string') return j.output;
  if (j.output && typeof j.output.text === 'string') return j.output.text;
  if (j.completion) return j.completion;
  return '';
}

function stripFences(s) {
  if (!s) return '';
  let t = s.trim();
  // strip ```json ... ``` or ``` ... ```
  const fence = /^```(?:json)?\s*([\s\S]*?)\s*```$/i;
  const m = t.match(fence);
  if (m) t = m[1].trim();
  // also catch first { ... last }
  const first = t.indexOf('{');
  const last = t.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    t = t.slice(first, last + 1);
  }
  return t;
}

const raw = items[0] ? items[0].json : {};
const rawText = pickText(raw);
const cleaned = stripFences(rawText);

let parsed = {
  name: '',
  phone: '',
  state: '',
  cv_link: '',
  project_links: [],
  complete: false
};
let parse_error = false;

try {
  if (cleaned) {
    const j = JSON.parse(cleaned);
    parsed.name = (j.name || '').toString().trim();
    parsed.phone = (j.phone || '').toString().trim();
    parsed.state = (j.state || '').toString().trim();
    parsed.cv_link = (j.cv_link || '').toString().trim();
    parsed.project_links = Array.isArray(j.project_links)
      ? j.project_links.filter(x => typeof x === 'string' && x.trim()).map(x => x.trim())
      : [];
    // Recompute complete defensively
    parsed.complete = !!(parsed.name && parsed.phone && parsed.state && parsed.cv_link && parsed.project_links.length > 0);
  } else {
    parse_error = true;
  }
} catch (e) {
  parse_error = true;
  parsed.complete = false;
}

const project_links_str = parsed.project_links.join(', ');

return [{
  json: {
    sender_id,
    post_id,
    message_text,
    name: parsed.name,
    phone: parsed.phone,
    state: parsed.state,
    cv_link: parsed.cv_link,
    project_links: parsed.project_links,
    project_links_str,
    complete: parsed.complete,
    parse_error
  }
}];

