// Extract text from CV. Handle PDF (binary), HTML, and plain text. Never throw.
// Truncate to ~4000 chars. On any failure: cv_text='', cv_extraction_failed=true.

const upstream = $('Normalize Parsed Info').first().json;
const base = { ...upstream };

async function extract() {
  try {
    const item = items[0];
    if (!item) return { cv_text: '', cv_extraction_failed: true, cv_error: 'no_item' };

    // Detect binary (PDF or other file)
    const binaryKeys = item.binary ? Object.keys(item.binary) : [];
    if (binaryKeys.length > 0) {
      const bin = item.binary[binaryKeys[0]];
      const mime = (bin.mimeType || '').toLowerCase();
      const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKeys[0]);

      if (mime.includes('pdf') || (bin.fileName && bin.fileName.toLowerCase().endsWith('.pdf'))) {
        // Lightweight PDF text extraction without pdf-parse: pull text between BT...ET ops & ()s
        // This is intentionally crude — good enough for triage screening.
        const raw = buffer.toString('latin1');
        const matches = raw.match(/\(([^()\\]{2,})\)/g) || [];
        let text = matches.map(s => s.slice(1, -1)).join(' ');
        text = text.replace(/\s+/g, ' ').trim();
        if (!text) {
          return { cv_text: '', cv_extraction_failed: true, cv_error: 'pdf_no_text_extracted' };
        }
        return { cv_text: text.slice(0, 4000), cv_extraction_failed: false };
      }

      // Treat as text
      const asText = buffer.toString('utf8').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
      return { cv_text: asText.slice(0, 4000), cv_extraction_failed: !asText };
    }

    // Non-binary: maybe HTML string body
    const j = item.json || {};
    let html = '';
    if (typeof j === 'string') html = j;
    else if (typeof j.body === 'string') html = j.body;
    else if (typeof j.data === 'string') html = j.data;
    else html = JSON.stringify(j);

    const text = html.replace(/<script[\s\S]*?<\/script>/gi, ' ')
                     .replace(/<style[\s\S]*?<\/style>/gi, ' ')
                     .replace(/<[^>]+>/g, ' ')
                     .replace(/&nbsp;/g, ' ')
                     .replace(/\s+/g, ' ')
                     .trim();

    if (!text) return { cv_text: '', cv_extraction_failed: true, cv_error: 'empty_after_strip' };
    return { cv_text: text.slice(0, 4000), cv_extraction_failed: false };
  } catch (e) {
    return { cv_text: '', cv_extraction_failed: true, cv_error: e.message };
  }
}

const res = await extract.call(this);
return [{ json: { ...base, ...res } }];

// For each fetched portfolio link result: strip HTML, truncate ~1500 chars,
// note thin/empty as image-heavy page. Combine all with separators.
// Always succeed — never throw.

const cvCtx = $('Extract CV Text').first().json;
const links = Array.isArray(cvCtx.project_links) ? cvCtx.project_links : [];

const combined = [];
let idx = 0;
for (const item of items) {
  const url = (item.json && (item.json.project_links || item.json.url)) || links[idx] || `link_${idx + 1}`;
  let raw = '';
  try {
    const j = item.json || {};
    if (typeof j === 'string') raw = j;
    else if (typeof j.body === 'string') raw = j.body;
    else if (typeof j.data === 'string') raw = j.data;
    else if (j.error) raw = '';
    else raw = '';
  } catch (e) { raw = ''; }

  let text = '';
  try {
    text = String(raw)
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  } catch (e) { text = ''; }

  let section;
  if (!text || text.length < 80) {
    section = `--- ${url} ---\n[Could not extract meaningful text - likely image-heavy page]`;
  } else {
    section = `--- ${url} ---\n${text.slice(0, 1500)}`;
  }
  combined.push(section);
  idx++;
}

const portfolio_text_combined = combined.join('\n\n') || '[No portfolio links provided or all fetches failed]';

return [{
  json: {
    ...cvCtx,
    portfolio_text_combined,
    portfolio_links_count: links.length
  }
}];

// Build the sheet row. Defensively parse Claude's review JSON. Never throw.

const ctx = $('Extract Portfolio Text').first().json;
const ai = items[0] ? items[0].json : {};

function pickText(j) {
  if (!j) return '';
  if (typeof j === 'string') return j;
  if (typeof j.text === 'string') return j.text;
  if (Array.isArray(j.content)) {
    return j.content.map(c => (c && (c.text || c.value)) || '').join('\n');
  }
  if (j.message && Array.isArray(j.message.content)) {
    return j.message.content.map(c => (c && (c.text || c.value)) || '').join('\n');
  }
  if (j.message && typeof j.message.content === 'string') return j.message.content;
  if (typeof j.output === 'string') return j.output;
  if (j.completion) return j.completion;
  return '';
}

function stripFences(s) {
  if (!s) return '';
  let t = s.trim();
  const m = t.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
  if (m) t = m[1].trim();
  const first = t.indexOf('{');
  const last = t.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) t = t.slice(first, last + 1);
  return t;
}

let summary = '';
let score = 0;
let recommendation = 'Pass';

try {
  const cleaned = stripFences(pickText(ai));
  if (cleaned) {
    const j = JSON.parse(cleaned);
    summary = (j.summary || '').toString();
    const s = parseInt(j.score, 10);
    score = Number.isFinite(s) ? Math.max(0, Math.min(10, s)) : 0;
    const rec = (j.recommendation || '').toString();
    recommendation = ['Strong', 'Maybe', 'Pass'].includes(rec) ? rec : 'Pass';
  }
} catch (e) {
  summary = '[AI review parse failed: ' + e.message + ']';
  score = 0;
  recommendation = 'Pass';
}

const row = {
  Timestamp: new Date().toISOString(),
  'Post/Reel ID': ctx.post_id || '',
  Name: ctx.name || '',
  Phone: ctx.phone || '',
  State: ctx.state || '',
  'CV Link': ctx.cv_link || '',
  'Project Links': ctx.project_links_str || '',
  'AI Summary': summary,
  'AI Score': score,
  Recommendation: recommendation,
  Rank: ''
};

return [{
  json: {
    ...ctx,
    ai_summary: summary,
    ai_score: score,
    recommendation,
    row
  }
}];

// Compute competition ranking by AI Score (desc). Ties share rank.
// Match THIS applicant's row by Timestamp + Name fallback; if no match, fall back gracefully.

const prepared = $('Prepare Sheet Row').first().json;
const myTimestamp = prepared.row.Timestamp;
const myName = prepared.row.Name;
const myScore = Number(prepared.row['AI Score']) || 0;

const rows = items.map(i => i.json).filter(r => r && (r.Name || r.name));

// Normalize key access (Sheet headers might be exact-case)
function g(r, key) {
  if (r[key] !== undefined) return r[key];
  const lower = key.toLowerCase();
  for (const k of Object.keys(r)) {
    if (k.toLowerCase() === lower) return r[k];
  }
  return undefined;
}

// Build score list
const scored = rows.map((r, i) => ({
  idx: i,
  timestamp: g(r, 'Timestamp') || '',
  name: g(r, 'Name') || '',
  score: Number(g(r, 'AI Score')) || 0,
  row: r
}));

// Sort desc by score
scored.sort((a, b) => b.score - a.score);

// Competition ranking (1,2,2,4,...)
let rank = 0;
let lastScore = null;
let seen = 0;
for (const s of scored) {
  seen++;
  if (s.score !== lastScore) {
    rank = seen;
    lastScore = s.score;
  }
  s.rank = rank;
}

// Find my row
let mine = scored.find(s => s.timestamp === myTimestamp && s.name === myName);
if (!mine) mine = scored.find(s => s.timestamp === myTimestamp);
if (!mine) mine = scored.find(s => s.name === myName && s.score === myScore);

let myRank = mine ? mine.rank : (scored.length || 1);
// Sheet row number = header (1) + position in original rows + 1
let mySheetRow = mine ? (mine.idx + 2) : null;

return [{
  json: {
    ...prepared,
    computed_rank: myRank,
    target_sheet_row: mySheetRow,
    rank_match_ok: !!mine,
    total_applicants: scored.length
  }
}];

